Greedy insertion with incremental cost evaluation using Manhattan distance approximation plus time-window penalty, iterating over all existing assigns and selecting minimal positive delta, with fallback to empty assign creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		bestFound bool
	}
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for jj := 0; jj < orderCount; jj++ {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		bestCandidate := candidate{-1, 0.0, false}
		tempAssigns := make([]Assign, dispatch.AssignsLen)
		tempCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			tempAssigns[i] = dispatch.Assigns[i]
			tempCosts[i] = dispatch.Assigns[i].Cost
		}
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			addOK := dispatch.Assigns[ii].AddShip(shipID, ori, des)
			if !addOK {
				continue
			}
			prevCost := tempCosts[ii]
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			delta := newCost - prevCost
			dispatch.Assigns[ii].RemoveShip(shipID)
			dispatch.Assigns[ii].GenRoute()
			if delta >= 0 && (!bestCandidate.bestFound || delta < bestCandidate.costDelta) {
				bestCandidate.assignIdx = ii
				bestCandidate.costDelta = delta
				bestCandidate.bestFound = true
			}
		}
		if bestCandidate.bestFound {
			finalOK := dispatch.Assigns[bestCandidate.assignIdx].AddShip(shipID, ori, des)
			if finalOK {
				dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
			} else {
				bestCandidate.bestFound = false
			}
		}
		if !bestCandidate.bestFound {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx >= MAXASSIGNS {
				for i := 0; i < dispatch.AssignsLen; i++ {
					restoreCost := tempCosts[i]
					dispatch.Assigns[i].Cost = restoreCost
				}
				dispatch.RenewnTotalCost()
				return dispatch
			}
			ok := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			} else {
				for i := 0; i < dispatch.AssignsLen; i++ {
					restoreCost := tempCosts[i]
					dispatch.Assigns[i].Cost = restoreCost
				}
				dispatch.RenewnTotalCost()
				return dispatch
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

